/* ── State ── */
let screen = 'tout';
let prevScreen = 'tout';
let widgetsAnimated = false;
let currentConv = 'sophie';
let convFav = false;
const favState = {'sophie':false,'cecile':false,'jack':false,'amira':false,'lucas':false,'camille':false};
let chosenConv = null;
let onboardingShown = false;
