let rejectVisitAnswer = 'oui';
let pendingAction = null;
const filters = {
  tout: {favoris:false, nonlus:false},
  proprio: {favoris:false, dossier:false, refuse:false, incomplet:false, visite:false, nonlus:false}
};



/* ── Init ── */
window.addEventListener('DOMContentLoaded', () => {
  showScreen('tout');
  updateChips('tout');
  updateChips('proprio');
  applyFilters('tout');
  applyFilters('proprio');
  requestAnimationFrame(() => {
    setTimeout(showInitialOnboarding, 250);
  });
  // V10: long press replaces swipe for favourites
  ['ci-sophie-proprio','ci-cecile-proprio'].forEach(id => {
    const el = document.getElementById(id);
    if (el) setupLongPress(el, el.dataset.name);
  });
});

/* ── Screens ── */
function hideTransientUI(skipOnboard) {
  document.querySelectorAll('.dropdown').forEach(d => d.classList.remove('open'));
  document.querySelectorAll('.overlay').forEach(o => {
    if (skipOnboard && o.id === 'ov-onboard') return;
    o.classList.remove('open');
  });
  document.getElementById('ov-mode')?.classList.remove('open');
}

function showScreen(id) {
  const target = document.getElementById('s-' + id);
  if (!target) return;
  hideTransientUI();
  document.querySelectorAll('.screen').forEach(s => {
    s.classList.remove('active');
    s.setAttribute('aria-hidden', 'true');
  });
  target.classList.add('active');
  target.setAttribute('aria-hidden', 'false');
  target.scrollTop = 0;
  prevScreen = screen; screen = id;
}
function goBack() { showScreen(prevScreen === 'conv' ? 'proprio' : prevScreen); }

function resetProprioScreenState() {
  filters.proprio = {favoris:false,dossier:false,refuse:false,incomplet:false,visite:false,nonlus:false};
  updateChips('proprio');

  const list = document.getElementById('list-proprio');
  if (list) {
    list.querySelectorAll('[data-name]').forEach(el => {
      const wrap = el.closest('.swipe-wrap') || el;
      wrap.style.display = '';
    });
    list.scrollTop = 0;
  }

  document.getElementById('chosen-banner')?.classList.remove('show');
  document.getElementById('empty-proprio')?.classList.remove('show');
  applyFilters('proprio');
}

function enterProprioDemo() {
  closeOv('ov-onboard');
  closeModeBS();
  resetProprioScreenState();
  showScreen('proprio');
}

/* ── Mode switching ── */
function switchMode(mode) {
  hideTransientUI();
  if (mode === 'proprio') {
    resetProprioScreenState();
    showScreen('proprio');
  } else {
    filters.tout = {favoris:false,nonlus:false};
    updateChips('tout'); applyFilters('tout');
    showScreen('tout');
  }
}

/* ── Dropdown ── */
function openDD(id, e) {
  if (e) { e.stopPropagation(); e.preventDefault(); }
  const dd = document.getElementById(id);
  const isOpen = dd.classList.contains('open');
  document.querySelectorAll('.dropdown').forEach(d => d.classList.remove('open'));
  if (!isOpen) {
    // Ancrer sur le phone frame, pas sur le bouton (invariant au scroll du filter-row)
    const phone = document.getElementById('phone');
    const phoneRect = phone.getBoundingClientRect();
    // Position fixe : 8px sous le filter-row, aligné à gauche du phone + 16px padding
    const filterRow = e ? e.currentTarget.closest('.filter-row') : null;
    let top, left;
    if (filterRow) {
      const fr = filterRow.getBoundingClientRect();
      top = fr.bottom + 4;
    } else {
      top = phoneRect.top + 120;
    }
    left = phoneRect.left + 16;
    dd.style.top = top + 'px';
    dd.style.left = left + 'px';
    dd.classList.add('open');
  }
}
function closeDD(id) { document.getElementById(id)?.classList.remove('open'); }
document.addEventListener('click', e => {
  if (!e.target.closest('.dropdown') && !e.target.closest('.chip')) {
    document.querySelectorAll('.dropdown').forEach(d => d.classList.remove('open'));
  }
});

/* ── Overlays ── */
function openOv(id) { document.getElementById(id)?.classList.add('open'); }
function closeOv(id) { document.getElementById(id)?.classList.remove('open'); }

function showInitialOnboarding() {
  if (onboardingShown) return;
  onboardingShown = true;
  openOv('ov-onboard');
}

