/* ── Conversation ── */
function escapeHtml(value) {
  return String(value)
    .replaceAll('&', '&amp;')
    .replaceAll('<', '&lt;')
    .replaceAll('>', '&gt;')
    .replaceAll('"', '&quot;')
    .replaceAll("'", '&#39;');
}

function renderConversationFallback(conv) {
  const msgsArea = document.getElementById('msgs-area');
  if (!msgsArea || !conv) return;
  const lastMsg = Array.isArray(conv.msgs) && conv.msgs.length ? conv.msgs[conv.msgs.length - 1] : null;
  msgsArea.innerHTML = `
    <div class="msg-row">
      <div class="msg-av-wrap"><div class="msg-av"><img src="${conv.avatar}" alt=""></div></div>
      <div class="msg-grp">
        <div class="bubble">${escapeHtml(lastMsg?.text || 'Conversation indisponible.')}</div>
        <div class="msg-time">${escapeHtml(lastMsg?.time || '')}</div>
      </div>
    </div>
  `;
}

function goToConv(name) {
  currentConv = name;
  const conv = CONV[name];
  if (!conv) return;
  try {
    // Populate new conv header
    const thumbEl = document.getElementById('conv-hdr-thumb');
    const personEl = document.getElementById('conv-hdr-person');
    if (thumbEl) {
      const aptImgEl = document.querySelector('.dbl-thumb img');
      if (aptImgEl) {
        const img = document.createElement('img');
        img.src = aptImgEl.src;
        img.alt = '';
        thumbEl.innerHTML = '';
        thumbEl.appendChild(img);
      }
    }
    if (personEl) {
      const avatarSrc2 = conv.avatar || '';
      if (avatarSrc2) {
        const img = document.createElement('img');
        img.src = avatarSrc2;
        img.alt = '';
        personEl.innerHTML = '';
        personEl.appendChild(img);
      } else {
        personEl.innerHTML = '';
      }
    }
    // Build subtitle
    const subtitleP = document.getElementById('conv-hdr-subtitle');
    if (subtitleP && conv.name) {
      const parts = conv.name.split(' ');
      const shortName = parts[0] + (parts[1] ? ' ' + parts[1][0] + '.' : '');
      subtitleP.innerHTML = '<strong>' + shortName + '</strong> · ' + (conv.title || '');
    }
    updateConversationHeaderAction();
    const ATTACH = `<div class="attach-card">
      <div class="attach-icon"><svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 256 256" fill="#497e64"><path d="M245,110.64A16,16,0,0,0,232,104H216V88a16,16,0,0,0-16-16H130.67L102.94,51.2a16.14,16.14,0,0,0-9.6-3.2H40A16,16,0,0,0,24,64V208a8,8,0,0,0,8,8H211.1a8,8,0,0,0,7.59-5.47l28.49-85.47A16,16,0,0,0,245,110.64ZM93.34,64l27.72,20.8a16.12,16.12,0,0,0,9.6,3.2H200v16H69.77a16,16,0,0,0-15.18,10.94L40,158.7V64Z"/></svg></div>
      <div><div class="attach-name">order126725.pdf</div><div class="attach-type">PDF</div></div>
    </div>`;

    let msgsHtml = '';
    const avatarSrc = conv.avatar || conv.personUrl || '';
    const avatarHtml = avatarSrc ? `<img src="${avatarSrc}" alt="">` : `<span style="font-size:16px;font-weight:700;color:${conv.textColor||'#2e6148'};font-family:'Satoshi',sans-serif;">${conv.initials||'?'}</span>`;
    const avatarStyle = avatarSrc ? '' : `background:${conv.color||'#c8ddd4'};display:flex;align-items:center;justify-content:center;`;
    (conv.msgs || []).forEach(m => {
      const safeText = escapeHtml(m.text || '').replace(/\n/g, '<br>');
      const safeTime = escapeHtml(m.time || '');
      if (m.from === 'them') {
        msgsHtml += `<div class="msg-row">
          <div class="msg-av-wrap"><div class="msg-av" style="${avatarStyle}">${avatarHtml}</div></div>
          <div class="msg-grp">
            <div class="bubble">${safeText}</div>
            <div class="msg-time">${safeTime}</div>
          </div></div>`;
      } else {
        msgsHtml += `<div class="msg-row sent"><div class="msg-grp sent">
          ${m.attach ? ATTACH : ''}
          <div class="bubble sent">${safeText}</div>
          <div class="msg-time sent">${safeTime}</div>
        </div></div>`;
      }
    });

    if (conv.widgets) {
      const isFav = favState[name] || false;
      const hasChosenAnother = Boolean(chosenConv && chosenConv !== name);
      const decisionHtml = chosenConv === name ? `
        <div class="action-wrap" onclick="openAttente()">
          <button type="button" class="action-btn" style="background:#f2f2f2"><svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 256 256" fill="#727373"><path d="M128,24A104,104,0,1,0,232,128,104.11,104.11,0,0,0,128,24Zm0,192a88,88,0,1,1,88-88A88.1,88.1,0,0,1,128,216Zm64-88a8,8,0,0,1-8,8H128a8,8,0,0,1-8-8V72a8,8,0,0,1,16,0v48h48A8,8,0,0,1,192,128Z"/></svg></button>
          <span class="action-label" style="font-size:11px;white-space:nowrap;">En attente</span>
        </div>` : `
        <div class="action-wrap" onclick="openRejeter()">
          <button type="button" class="action-btn" style="background:#f2f2f2"><svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 256 256" fill="#061f18"><path d="M205.66,194.34a8,8,0,0,1-11.32,11.32L128,139.31,61.66,205.66a8,8,0,0,1-11.32-11.32L116.69,128,50.34,61.66A8,8,0,0,1,61.66,50.34L128,116.69l66.34-66.35a8,8,0,0,1,11.32,11.32L139.31,128Z"/></svg></button>
          <span class="action-label">Rejeter</span>
        </div>
        ${hasChosenAnother ? '' : `
        <div class="action-wrap" onclick="openChoisir()">
          <button type="button" class="action-btn" style="background:#f0fdf0"><svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 256 256" fill="#497e64"><path d="M229.66,77.66l-128,128a8,8,0,0,1-11.32,0l-56-56a8,8,0,0,1,11.32-11.32L96,188.69,218.34,66.34a8,8,0,0,1,11.32,11.32Z"/></svg></button>
          <span class="action-label">Choisir</span>
        </div>`}
      `;
      msgsHtml += `<div class="action-bar" id="action-bar">
        <div class="action-wrap" onclick="toggleFav()">
          <button type="button" class="action-btn" id="btn-fav" style="background:#f2f2f2">
            <span id="fav-icon">${isFav ? SVG_HEART_F : SVG_HEART_O}</span>
          </button>
          <span class="action-label">Favoris</span>
        </div>
        <div class="action-wrap" onclick="openDossier()">
          <button type="button" class="action-btn" style="background:#f2f2f2"><svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 256 256" fill="currentColor"><path d="M216,72H130.67L102.94,51.2A16.12,16.12,0,0,0,93.34,48H40A16,16,0,0,0,24,64V192a16,16,0,0,0,16,16H216a16,16,0,0,0,16-16V88A16,16,0,0,0,216,72Zm0,120H40V64H93.34l27.73,20.8A16.12,16.12,0,0,0,130.67,88H216Z"/></svg></button>
          <span class="action-label">Dossier</span>
        </div>
        ${decisionHtml}
      </div>`;
    }

    document.getElementById('msgs-area').innerHTML = msgsHtml;
    widgetsAnimated = false;
    if (conv.widgets) {
      setTimeout(() => {
        const bar = document.getElementById('action-bar');
        if (bar) { bar.classList.add('anim'); widgetsAnimated = true; }
      }, 150);
    }
  } catch (err) {
    console.error('goToConv failed', err);
    renderConversationFallback(conv);
  }

  showScreen('conv');
}

